import React, { useState, useRef, useEffect } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import "./styles.css";

interface Candidate {
  id: string;
  name: string;
  match_score: number;
  rerank_score: number;
  skill_score: number;
  final_score: number;
  technical_skills?: string;
}

interface Analysis {
  category: string;
  experience_level: string;
  technical_skills: string[];
  summary: string;
}

// ← اللوكل
const API_BASE_URL = "http://localhost:8000";

export default function App() {
  const [jdText, setJdText]     = useState<string>("");
  const [loading, setLoading]   = useState<boolean>(false);
  const [results, setResults]   = useState<Candidate[]>([]);
  const [analysis, setAnalysis] = useState<Analysis | null>(null);
  const [error, setError]       = useState<string>("");

  const [chatInput, setChatInput]       = useState("");
  const [chatMessages, setChatMessages] = useState<{ role: string; text: string }[]>([]);
  const [chatHistory, setChatHistory]   = useState<any[]>([]);
  const [chatLoading, setChatLoading]   = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatMessages]);

  const startMatching = async () => {
    if (!jdText.trim()) return;
    setError("");
    setLoading(true);
    setResults([]);
    setAnalysis(null);
    setChatMessages([]);
    setChatHistory([]);

    try {
      const response = await axios.post(`${API_BASE_URL}/search`, {
        job_description: jdText,
        top_k: 10,
      });
      setResults(response.data.candidates);
      setAnalysis(response.data.analysis);
    } catch (err) {
      setError("Connection failed! Make sure the backend is running.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim() || results.length === 0) return;
    const userMsg = chatInput;
    setChatInput("");
    setChatMessages((prev) => [...prev, { role: "user", text: userMsg }]);
    setChatLoading(true);

    try {
      const response = await axios.post(`${API_BASE_URL}/chat`, {
        question: userMsg,
        history: chatHistory,
        candidate_ids: results.map((c) => c.id),
      });
      setChatHistory(response.data.history);
      setChatMessages((prev) => [...prev, { role: "ai", text: response.data.answer }]);
    } catch {
      setChatMessages((prev) => [...prev, { role: "ai", text: "Connection error." }]);
    } finally {
      setChatLoading(false);
    }
  };

  return (
    <div className="luxury-container">
      <div className="bg-glow"></div>

      <header className="premium-nav">
        <div className="nav-content">
          <div className="brand-suite">
            <h1 className="logo-text">ITG <span>PRO</span></h1>
            <div className="status-badge">AI TALENT INTELLIGENCE</div>
          </div>
          {analysis && (
            <div className="analysis-pills">
              <span className="pill">{analysis.category}</span>
              <span className="pill pill-level">{analysis.experience_level}</span>
            </div>
          )}
        </div>
      </header>

      <main className="split-view">
        {/* LEFT PANEL */}
        <section className="input-panel">
          <div className="panel-inner">
            <h2 className="section-title">Job Intelligence</h2>
            <p className="section-subtitle">Define the requirements to begin neural matching.</p>

            <div className="textarea-wrapper">
              <textarea
                value={jdText}
                onChange={(e) => setJdText(e.target.value)}
                placeholder="Paste Job Requirements..."
              />
              <div className="corner-decor top-left"></div>
              <div className="corner-decor bottom-right"></div>
            </div>

            {error && <p className="error-msg">{error}</p>}

            <button
              className={`match-trigger ${loading ? "loading" : ""}`}
              onClick={startMatching}
              disabled={loading}
            >
              {loading ? "Analyzing Patterns..." : "Initiate Neural Match"}
            </button>

            {/* Skills extracted */}
            {analysis?.technical_skills && analysis.technical_skills.length > 0 && (
              <div className="extracted-skills">
                <p className="skills-label">Extracted Skills</p>
                <div className="skills-row">
                  {analysis.technical_skills.slice(0, 6).map((s, i) => (
                    <span key={i} className="skill-chip">{s}</span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </section>

        {/* RIGHT PANEL */}
        <section className="output-panel">
          <div className="results-header">
            <h3>Matched Talent Pool</h3>
            <span className="count">{results.length} Candidates Found</span>
          </div>

          <div className="candidates-list">
            <AnimatePresence>
              {results.map((cand, idx) => (
                <motion.div
                  key={cand.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: idx * 0.07 }}
                  className="talent-card"
                >
                  <div className="card-rank">#{idx + 1}</div>
                  <div className="card-main">
                    <h4>{cand.name}</h4>
                    <span className="id-tag">REF: {cand.id}</span>
                    <div className="skill-preview">
                      {cand.technical_skills?.split(",").slice(0, 3).map((s) => (
                        <span key={s} className="mini-tag">{s.trim()}</span>
                      ))}
                    </div>
                    {/* Score bars */}
                    <div className="score-bars">
                      <div className="bar-row">
                        <span>Semantic</span>
                        <div className="bar-bg"><div className="bar-fill" style={{ width: `${cand.match_score * 100}%` }} /></div>
                        <span>{Math.round(cand.match_score * 100)}%</span>
                      </div>
                      <div className="bar-row">
                        <span>Rerank</span>
                        <div className="bar-bg"><div className="bar-fill bar-blue" style={{ width: `${cand.rerank_score * 100}%` }} /></div>
                        <span>{Math.round(cand.rerank_score * 100)}%</span>
                      </div>
                      <div className="bar-row">
                        <span>Skills</span>
                        <div className="bar-bg"><div className="bar-fill bar-green" style={{ width: `${cand.skill_score * 100}%` }} /></div>
                        <span>{Math.round(cand.skill_score * 100)}%</span>
                      </div>
                    </div>
                  </div>

                  {/* Circular score */}
                  <div className="card-score">
                    <div className="score-circle">
                      <svg viewBox="0 0 36 36">
                        <path className="circle-bg" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
                        <path className="circle" strokeDasharray={`${Math.round(cand.final_score * 100)}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
                      </svg>
                      <div className="percentage">{Math.round(cand.final_score * 100)}%</div>
                    </div>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>

            {!loading && results.length === 0 && (
              <div className="placeholder-state">
                <div className="pulse-icon">◈</div>
                <p>System Ready for Input</p>
              </div>
            )}
          </div>

          {/* CHAT */}
          {results.length > 0 && (
            <div className="ai-chat-overlay">
              <div className="chat-header">
                <span>◈ AI Insight Engine</span>
              </div>
              <div className="chat-history">
                {chatMessages.length === 0 && (
                  <p className="chat-hint">Ask about candidate suitability...</p>
                )}
                {chatMessages.map((msg, i) => (
                  <div key={i} className={`chat-bubble ${msg.role}`}>{msg.text}</div>
                ))}
                {chatLoading && <div className="typing-dot">Analyzing...</div>}
                <div ref={chatEndRef} />
              </div>
              <div className="chat-input">
                <input
                  value={chatInput}
                  onChange={(e) => setChatInput(e.target.value)}
                  placeholder="Ask about candidates..."
                  onKeyDown={(e) => e.key === "Enter" && handleChat()}
                />
                <button onClick={handleChat} disabled={chatLoading}>◈</button>
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
}
